+  cursor?: string;
+  batchSize?: number;
+};
+
+export async function backfillLedger(options: BackfillLedgerOptions = {}) {
+  const limit = options.batchSize ?? readIntEnv("LEDGER_BACKFILL_BATCH_SIZE", 500);
+  const lastSeen = options.cursor ?? "";
+  const batch = [...db.invoices.values()]
+    .filter((invoice) => invoice.id > lastSeen)
+    .sort((a, b) => a.id.localeCompare(b.id))
+    .slice(0, limit);
+
+  for (const invoice of batch) {
+    await writeLedgerEvent({
+      type: "invoice.paid",
+      invoice,
+      idempotencyKey: `backfill:invoice:${invoice.id}:paid`,
+    });
+  }
+
+  const nextCursor = batch.at(-1)?.id ?? lastSeen;
+  return {
+    processed: batch.length,
+    cursor: nextCursor,
+    done: batch.length < limit,
+  };
 }

import { db } from "../db/client";
import type { Invoice, LedgerEvent, Refund } from "../db/types";
import { assertCents } from "../lib/money";

type LedgerEventInput =
  | { type: "invoice.paid"; invoice: Invoice; idempotencyKey: string }
  | { type: "refund.created"; refund: Refund; invoice?: Invoice; idempotencyKey: string };

function safePayload(input: LedgerEventInput): LedgerEvent["payload"] {
  if (input.type === "invoice.paid") {
    return {
      invoiceId: input.invoice.id,
      subscriptionId: input.invoice.subscriptionId,
      status: "paid",
    };
  }

  return {
    refundId: input.refund.id,
    invoiceId: input.refund.invoiceId,
    invoiceStatus: input.invoice ? "refunded" : null,
  };
}

export async function writeLedgerEvent(input: LedgerEventInput): Promise<LedgerEvent> {
  const existing = db.ledgerEvents.get(input.idempotencyKey);
  if (existing) return existing;

  const base = input.type === "invoice.paid" ? input.invoice : input.refund;
  assertCents(base.amountCents);

  const event: LedgerEvent = {
    id: `evt_${input.idempotencyKey}`,
    type: input.type,
    schemaVersion: 2,
    idempotencyKey: input.idempotencyKey,
    accountId: input.type === "invoice.paid" ? input.invoice.accountId : input.invoice?.accountId ?? "",
    invoiceId: input.type === "invoice.paid" ? input.invoice.id : input.refund.invoiceId,
    subscriptionId: input.type === "invoice.paid" ? input.invoice.subscriptionId : input.invoice?.subscriptionId,
    refundId: input.type === "refund.created" ? input.refund.id : undefined,
    amountCents: base.amountCents,
    currency: base.currency,
    region: base.region,
    createdAt: base.createdAt,
    payload: safePayload(input),
  };

  db.ledgerEvents.set(event.idempotencyKey, event);
  return event;
}
import { db } from "../db/client";
import type { Invoice } from "../db/types";

export function listInvoicesFromLedger(): Invoice[] {
  const invoices = new Map<string, Invoice>();

  for (const event of db.ledgerEvents.values()) {
    if (event.type === "invoice.paid") {
      invoices.set(event.invoiceId, {
        id: event.invoiceId,
        accountId: event.accountId,
        subscriptionId: event.subscriptionId ?? "",
        amountCents: event.amountCents,
        currency: event.currency,
        region: event.region,
        status: "paid",
        createdAt: event.createdAt,
      });
    }

    if (event.type === "refund.created") {
      const invoice = invoices.get(event.invoiceId);
      if (invoice) invoices.set(invoice.id, { ...invoice, status: "refunded" });
    }
  }

  return [...invoices.values()].sort((a, b) => a.createdAt.localeCompare(b.createdAt));
}
